interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: FieldRange[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 6 }    // dayOfWeek (0=Sunday, 6=Saturday)
];

function parseField(field: string, range: FieldRange): number[] {
  const values: number[] = [];

  // Handle comma-separated values
  if (field.includes(',')) {
    const parts = field.split(',');
    for (const part of parts) {
      values.push(...parseField(part.trim(), range));
    }
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Handle step values (e.g., "*/15" or "1-10/2")
  if (field.includes('/')) {
    const [base, stepStr] = field.split('/');
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    if (base === '*') {
      for (let i = range.min; i <= range.max; i += step) {
        values.push(i);
      }
    } else if (base.includes('-')) {
      const [startStr, endStr] = base.split('-');
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);

      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range: ${base}`);
      }

      if (start < range.min || end > range.max || start > end) {
        throw new Error(`Invalid range: ${base} for valid range ${range.min}-${range.max}`);
      }

      for (let i = start; i <= end; i += step) {
        values.push(i);
      }
    } else {
      const start = parseInt(base, 10);

      if (isNaN(start)) {
        throw new Error(`Invalid value: ${base}`);
      }

      if (start < range.min || start > range.max) {
        throw new Error(`Invalid value: ${base} for valid range ${range.min}-${range.max}`);
      }

      for (let i = start; i <= range.max; i += step) {
        values.push(i);
      }
    }

    return values;
  }

  // Handle ranges (e.g., "1-5")
  if (field.includes('-')) {
    const [startStr, endStr] = field.split('-');
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${field}`);
    }

    if (start < range.min || end > range.max || start > end) {
      throw new Error(`Invalid range: ${field} for valid range ${range.min}-${range.max}`);
    }

    for (let i = start; i <= end; i++) {
      values.push(i);
    }

    return values;
  }

  // Handle wildcards
  if (field === '*') {
    for (let i = range.min; i <= range.max; i++) {
      values.push(i);
    }
    return values;
  }

  // Handle single numbers
  const num = parseInt(field, 10);

  if (isNaN(num) || num < range.min || num > range.max) {
    throw new Error(`Invalid value: ${field} for valid range ${range.min}-${range.max}`);
  }

  return [num];
}

export default function parseCron(cronExpression: string): CronExpression {
  const fields = cronExpression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Invalid cron expression: expected 5 fields, got ${fields.length}`);
  }

  return {
    minute: parseField(fields[0], FIELD_RANGES[0]),
    hour: parseField(fields[1], FIELD_RANGES[1]),
    dayOfMonth: parseField(fields[2], FIELD_RANGES[2]),
    month: parseField(fields[3], FIELD_RANGES[3]),
    dayOfWeek: parseField(fields[4], FIELD_RANGES[4])
  };
}

class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const timePassed = now - this.lastRefillTime;
    const intervalsElapsed = timePassed / this.refillIntervalMs;
    const tokensToAdd = intervalsElapsed * this.refillRate;

    this.tokens = Math.min(this.maxTokens, this.tokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) {
      return true;
    }

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) {
      return;
    }

    while (!this.tryConsume(tokens)) {
      const tokensNeeded = tokens - this.tokens;

      if (this.refillRate > 0) {
        const tokensPerMs = this.refillRate / this.refillIntervalMs;
        const waitMs = Math.ceil(tokensNeeded / tokensPerMs);
        await new Promise(resolve => setTimeout(resolve, Math.max(1, waitMs)));
      } else {
        await new Promise(resolve => setTimeout(resolve, 10));
      }
    }
  }
}

