interface CronParsed {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 }
};

function parseField(field: string, range: { min: number; max: number }): number[] {
  if (field === '*') {
    return Array.from(
      { length: range.max - range.min + 1 },
      (_, i) => range.min + i
    );
  }

  // Handle step values (e.g., "*/15" or "1-10/2")
  if (field.includes('/')) {
    const [rangePart, stepPart] = field.split('/');
    const step = parseInt(stepPart, 10);

    let start = range.min;
    let end = range.max;

    if (rangePart !== '*') {
      const [s, e] = rangePart.split('-').map(x => parseInt(x, 10));
      start = s;
      end = e || s;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  // Handle ranges (e.g., "1-5")
  if (field.includes('-')) {
    const [start, end] = field.split('-').map(x => parseInt(x, 10));
    const result: number[] = [];
    for (let i = start; i <= end; i++) {
      result.push(i);
    }
    return result;
  }

  // Handle comma-separated lists (e.g., "1,3,5")
  if (field.includes(',')) {
    return field.split(',').map(s => parseInt(s.trim(), 10));
  }

  // Single number
  return [parseInt(field, 10)];
}

export default function parseCron(cronExpression: string): CronParsed {
  const fields = cronExpression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error('Cron expression must have exactly 5 fields');
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;

  const result: CronParsed = {
    minute: parseField(minuteField, FIELD_RANGES.minute),
    hour: parseField(hourField, FIELD_RANGES.hour),
    dayOfMonth: parseField(dayOfMonthField, FIELD_RANGES.dayOfMonth),
    month: parseField(monthField, FIELD_RANGES.month),
    dayOfWeek: parseField(dayOfWeekField, FIELD_RANGES.dayOfWeek)
  };

  // Validate values are within ranges
  const validate = (arr: number[], range: { min: number; max: number }, fieldName: string) => {
    for (const value of arr) {
      if (isNaN(value) || value < range.min || value > range.max) {
        throw new Error(`Invalid value in ${fieldName} field: ${value}`);
      }
    }
  };

  validate(result.minute, FIELD_RANGES.minute, 'minute');
  validate(result.hour, FIELD_RANGES.hour, 'hour');
  validate(result.dayOfMonth, FIELD_RANGES.dayOfMonth, 'dayOfMonth');
  validate(result.month, FIELD_RANGES.month, 'month');
  validate(result.dayOfWeek, FIELD_RANGES.dayOfWeek, 'dayOfWeek');

  return result;
}

