export default function flattenObject(
  obj: any,
  prefix: string = ""
): Record<string, any> {
  const result: Record<string, any> = {};

  for (const key in obj) {
    if (Object.prototype.hasOwnProperty.call(obj, key)) {
      const value = obj[key];
      const newKey = prefix ? `${prefix}.${key}` : key;

      if (
        value !== null &&
        typeof value === "object" &&
        !Array.isArray(value)
      ) {
        Object.assign(result, flattenObject(value, newKey));
      } else {
        result[newKey] = value;
      }
    }
  }

  return result;
}

class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: { maxTokens: number; refillRate: number; refillIntervalMs: number }) {
    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const timePassed = now - this.lastRefillTime;
    const intervalsElapsed = timePassed / this.refillIntervalMs;
    const tokensToAdd = intervalsElapsed * this.refillRate;
    this.tokens = Math.min(this.maxTokens, this.tokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) return true;
    this.refill();
    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return;
    while (true) {
      this.refill();
      if (this.tokens >= tokens) {
        this.tokens -= tokens;
        return;
      }
      const tokensNeeded = tokens - this.tokens;
      const timeNeeded = (tokensNeeded / this.refillRate) * this.refillIntervalMs;
      await new Promise(resolve => setTimeout(resolve, Math.max(1, timeNeeded)));
    }
  }
}

export default RateLimiter;

