interface CronParsed {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

export default function parseCron(expression: string): CronParsed {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;

  const parseField = (field: string, min: number, max: number): number[] => {
    const values = new Set<number>();
    const fieldParts = field.split(",");

    for (const part of fieldParts) {
      if (part === "*") {
        for (let i = min; i <= max; i++) {
          values.add(i);
        }
      } else if (part.includes("/")) {
        const [range, step] = part.split("/");
        const stepNum = parseInt(step, 10);

        if (isNaN(stepNum) || stepNum <= 0) {
          throw new Error(`Invalid step value: ${step}`);
        }

        let start = min;
        let end = max;

        if (range !== "*") {
          if (range.includes("-")) {
            const [rangeStart, rangeEnd] = range.split("-").map((x) => {
              const num = parseInt(x, 10);
              if (isNaN(num)) throw new Error(`Invalid number in range: ${x}`);
              return num;
            });
            start = rangeStart;
            end = rangeEnd;
          } else {
            const num = parseInt(range, 10);
            if (isNaN(num)) throw new Error(`Invalid number: ${range}`);
            start = num;
          }
        }

        for (let i = start; i <= end; i += stepNum) {
          if (i >= min && i <= max) {
            values.add(i);
          }
        }
      } else if (part.includes("-")) {
        const [rangeStart, rangeEnd] = part.split("-").map((x) => {
          const num = parseInt(x, 10);
          if (isNaN(num)) throw new Error(`Invalid number in range: ${x}`);
          return num;
        });

        if (rangeStart < min || rangeEnd > max || rangeStart > rangeEnd) {
          throw new Error(
            `Range out of bounds: ${part} (valid range: ${min}-${max})`
          );
        }

        for (let i = rangeStart; i <= rangeEnd; i++) {
          values.add(i);
        }
      } else {
        const num = parseInt(part, 10);

        if (isNaN(num)) {
          throw new Error(`Invalid value: ${part}`);
        }

        if (num < min || num > max) {
          throw new Error(
            `Value out of bounds: ${num} (valid range: ${min}-${max})`
          );
        }

        values.add(num);
      }
    }

    return Array.from(values).sort((a, b) => a - b);
  };

  return {
    minute: parseField(minuteStr, 0, 59),
    hour: parseField(hourStr, 0, 23),
    dayOfMonth: parseField(dayOfMonthStr, 1, 31),
    month: parseField(monthStr, 1, 12),
    dayOfWeek: parseField(dayOfWeekStr, 0, 6),
  };
}

