function parseCron(cronExpression: string): CronExpression {
  const fields = cronExpression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error("Cron expression must have exactly 5 fields");
  }

  const ranges = [
    { min: 0, max: 59 }, // minute
    { min: 0, max: 23 }, // hour
    { min: 1, max: 31 }, // dayOfMonth
    { min: 1, max: 12 }, // month
    { min: 0, max: 6 }, // dayOfWeek
  ];

  const fieldNames: (keyof CronExpression)[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];

  const parseField = (field: string, min: number, max: number): number[] => {
    const values = new Set<number>();

    const parts = field.split(",");

    for (const part of parts) {
      if (part.includes("/")) {
        const [rangePart, stepStr] = part.split("/");
        const step = parseInt(stepStr, 10);

        if (isNaN(step) || step <= 0) {
          throw new Error(`Invalid step value: ${stepStr}`);
        }

        if (rangePart === "*") {
          for (let i = min; i <= max; i += step) {
            values.add(i);
          }
        } else if (rangePart.includes("-")) {
          const [startStr, endStr] = rangePart.split("-");
          const start = parseInt(startStr, 10);
          const end = parseInt(endStr, 10);

          if (isNaN(start) || isNaN(end)) {
            throw new Error(`Invalid range: ${rangePart}`);
          }

          if (start < min || end > max || start > end) {
            throw new Error(
              `Range out of bounds: ${rangePart} (valid: ${min}-${max})`
            );
          }

          for (let i = start; i <= end; i += step) {
            values.add(i);
          }
        } else {
          throw new Error(`Invalid step syntax: ${part}`);
        }
      } else if (part.includes("-")) {
        const [startStr, endStr] = part.split("-");
        const start = parseInt(startStr, 10);
        const end = parseInt(endStr, 10);

        if (isNaN(start) || isNaN(end)) {
          throw new Error(`Invalid range: ${part}`);
        }

        if (start < min || end > max || start > end) {
          throw new Error(
            `Range out of bounds: ${part} (valid: ${min}-${max})`
          );
        }

        for (let i = start; i <= end; i++) {
          values.add(i);
        }
      } else if (part === "*") {
        for (let i = min; i <= max; i++) {
          values.add(i);
        }
      } else {
        const num = parseInt(part, 10);

        if (isNaN(num)) {
          throw new Error(`Invalid value: ${part}`);
        }

        if (num < min || num > max) {
          throw new Error(
            `Value out of range: ${num} (valid: ${min}-${max})`
          );
        }

        values.add(num);
      }
    }

    return Array.from(values).sort((a, b) => a - b);
  };

  const result: CronExpression = {
    minute: parseField(fields[0], ranges[0].min, ranges[0].max),
    hour: parseField(fields[1], ranges[1].min, ranges[1].max),
    dayOfMonth: parseField(fields[2], ranges[2].min, ranges[2].max),
    month: parseField(fields[3], ranges[3].min, ranges[3].max),
    dayOfWeek: parseField(fields[4], ranges[4].min, ranges[4].max),
  };

  return result;
}

