interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const RANGES: Record<keyof CronExpression, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function parseField(
  field: string,
  fieldName: keyof CronExpression,
  range: { min: number; max: number }
): number[] {
  const result = new Set<number>();

  const parts = field.split(',');

  for (const part of parts) {
    if (part.includes('/')) {
      const [base, stepStr] = part.split('/');
      const step = parseInt(stepStr, 10);

      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: ${stepStr}`);
      }

      let start = range.min;
      let end = range.max;

      if (base !== '*') {
        if (base.includes('-')) {
          const [startStr, endStr] = base.split('-');
          start = parseInt(startStr, 10);
          end = parseInt(endStr, 10);

          if (isNaN(start) || isNaN(end)) {
            throw new Error(`Invalid range: ${base}`);
          }
        } else {
          start = parseInt(base, 10);
          if (isNaN(start)) {
            throw new Error(`Invalid value: ${base}`);
          }
          end = range.max;
        }
      }

      for (let i = start; i <= end; i += step) {
        if (i >= range.min && i <= range.max) {
          result.add(i);
        }
      }
    } else if (part.includes('-')) {
      const [startStr, endStr] = part.split('-');
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);

      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range: ${part}`);
      }

      for (let i = start; i <= end; i++) {
        if (i >= range.min && i <= range.max) {
          result.add(i);
        }
      }
    } else if (part === '*') {
      for (let i = range.min; i <= range.max; i++) {
        result.add(i);
      }
    } else {
      const num = parseInt(part, 10);
      if (isNaN(num)) {
        throw new Error(`Invalid value: ${part}`);
      }
      if (num >= range.min && num <= range.max) {
        result.add(num);
      } else {
        throw new Error(`Value ${num} out of range [${range.min}, ${range.max}]`);
      }
    }
  }

  if (fieldName === 'dayOfWeek' && result.has(7)) {
    result.delete(7);
    result.add(0);
  }

  return Array.from(result).sort((a, b) => a - b);
}

function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${fields.length}`);
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;

  return {
    minute: parseField(minuteField, 'minute', RANGES.minute),
    hour: parseField(hourField, 'hour', RANGES.hour),
    dayOfMonth: parseField(dayOfMonthField, 'dayOfMonth', RANGES.dayOfMonth),
    month: parseField(monthField, 'month', RANGES.month),
    dayOfWeek: parseField(dayOfWeekField, 'dayOfWeek', RANGES.dayOfWeek),
  };
}

export default parseCron;

