interface CronParsed {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

export default function parseCron(expression: string): CronParsed {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error('Cron expression must have exactly 5 fields');
  }

  const ranges = [
    { min: 0, max: 59 },   // minute
    { min: 0, max: 23 },   // hour
    { min: 1, max: 31 },   // dayOfMonth
    { min: 1, max: 12 },   // month
    { min: 0, max: 7 }     // dayOfWeek
  ];

  const fieldNames = ['minute', 'hour', 'dayOfMonth', 'month', 'dayOfWeek'] as const;

  const result: CronParsed = {
    minute: [],
    hour: [],
    dayOfMonth: [],
    month: [],
    dayOfWeek: []
  };

  fields.forEach((field, index) => {
    const { min, max } = ranges[index];
    const fieldName = fieldNames[index];
    result[fieldName] = parseField(field, min, max);
  });

  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  if (field === '*') {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  if (field.includes('/')) {
    return parseStep(field, min, max);
  }

  if (field.includes(',')) {
    return parseList(field, min, max);
  }

  if (field.includes('-')) {
    return parseRange(field, min, max);
  }

  const num = parseInt(field, 10);
  if (isNaN(num) || num < min || num > max) {
    throw new Error(`Invalid cron value: ${field} is outside range [${min}, ${max}]`);
  }
  return [num];
}

function parseStep(field: string, min: number, max: number): number[] {
  const [base, step] = field.split('/');
  const stepNum = parseInt(step, 10);

  if (isNaN(stepNum) || stepNum <= 0) {
    throw new Error(`Invalid step value: ${step}`);
  }

  const start = base === '*' ? min : parseInt(base, 10);

  if (isNaN(start) || start < min || start > max) {
    throw new Error(`Invalid step base: ${base} is outside range [${min}, ${max}]`);
  }

  const result: number[] = [];
  for (let i = start; i <= max; i += stepNum) {
    result.push(i);
  }
  return result;
}

function parseRange(field: string, min: number, max: number): number[] {
  const [start, end] = field.split('-').map(s => parseInt(s, 10));

  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range: ${field}`);
  }

  if (start < min || start > max || end < min || end > max) {
    throw new Error(`Range ${field} is outside valid range [${min}, ${max}]`);
  }

  if (start > end) {
    throw new Error(`Invalid range: start (${start}) is greater than end (${end})`);
  }

  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function parseList(field: string, min: number, max: number): number[] {
  const values = field.split(',').map(item => {
    const num = parseInt(item.trim(), 10);
    if (isNaN(num) || num < min || num > max) {
      throw new Error(`Invalid cron value: ${num} is outside range [${min}, ${max}]`);
    }
    return num;
  });

  return Array.from(new Set(values)).sort((a, b) => a - b);
}

