}

function parseCron(expression: string): CronParsed {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error("Cron expression must have exactly 5 fields");
  }

  const ranges = [
    { min: 0, max: 59 },   // minute
    { min: 0, max: 23 },   // hour
    { min: 1, max: 31 },   // dayOfMonth
    { min: 1, max: 12 },   // month
    { min: 0, max: 6 }     // dayOfWeek
  ];

  const fieldNames: (keyof CronParsed)[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek"
  ];

  const result: CronParsed = {
    minute: [],
    hour: [],
    dayOfMonth: [],
    month: [],
    dayOfWeek: []
  };

  function parseField(fieldStr: string, min: number, max: number): number[] {
    const values = new Set<number>();
    const parts = fieldStr.split(",");

    function parseRange(rangeStr: string, step: number = 1): void {
      let start = min;
      let end = max;

      if (rangeStr === "*") {
        // Wildcard - use default min to max
      } else if (rangeStr.includes("-")) {
        const [rangeStart, rangeEnd] = rangeStr.split("-");
        start = parseInt(rangeStart, 10);
        end = parseInt(rangeEnd, 10);

        if (
          isNaN(start) ||
          isNaN(end) ||
          start < min ||
          end > max ||
          start > end
        ) {
          throw new Error(`Invalid range: ${rangeStr}`);
        }
      } else {
        start = parseInt(rangeStr, 10);
        end = start;

        if (isNaN(start) || start < min || start > max) {
          throw new Error(`Invalid value: ${rangeStr}`);
        }
      }

      for (let i = start; i <= end; i += step) {
        if (i >= min && i <= max) {
          values.add(i);
        }
      }
    }

    for (const part of parts) {
      if (part.includes("/")) {
        const [range, stepStr] = part.split("/");
        const step = parseInt(stepStr, 10);

        if (isNaN(step) || step <= 0) {
          throw new Error(`Invalid step value: ${stepStr}`);
        }

        parseRange(range, step);
      } else {
        parseRange(part);
      }
    }

    return Array.from(values).sort((a, b) => a - b);
  }

  for (let i = 0; i < 5; i++) {
    const range = ranges[i];
    const fieldName = fieldNames[i];
    result[fieldName] = parseField(fields[i], range.min, range.max);
  }

  return result;
}

