    let values: number[] = [];
    if (range === '*') {
      for (let i = min; i <= max; i += stepNum) {
        values.push(i);
      }
    } else if (range.includes('-')) {
      const parts = range.split('-');
      const rangeStart = parseInt(parts[0], 10);
      const rangeEnd = parseInt(parts[1], 10);
      if (isNaN(rangeStart) || isNaN(rangeEnd)) {
        throw new Error(`Invalid range: ${range}`);
      }
      for (let i = rangeStart; i <= rangeEnd; i += stepNum) {
        if (i >= min && i <= max) {
          values.push(i);
        }
      }
    } else {
      const start = parseInt(range, 10);
      if (isNaN(start)) {
        throw new Error(`Invalid step expression: ${field}`);
      }
      for (let i = start; i <= max; i += stepNum) {
        values.push(i);
      }
    }
    return values;
  }

  if (field.includes('-')) {
    const parts = field.split('-');
    if (parts.length !== 2) {
      throw new Error(`Invalid range: ${field}`);
    }
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${field}`);
    }
    if (start < min || end > max || start > end) {
      throw new Error(`Range ${start}-${end} outside valid range ${min}-${max}`);
    }
    const values = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  if (field.includes(',')) {
    const values = field.split(',').map(s => {
      const num = parseInt(s.trim(), 10);
      if (isNaN(num)) {
        throw new Error(`Invalid value in list: ${s}`);
      }
      if (num < min || num > max) {
        throw new Error(`Value ${num} outside valid range ${min}-${max}`);
      }
      return num;
    });
    return values;
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid cron field: ${field}`);
  }
  if (num < min || num > max) {
    throw new Error(`Value ${num} outside valid range ${min}-${max}`);
  }
  return [num];
}

