interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error('Cron expression must have exactly 5 fields');
  }

  const ranges = [
    { min: 0, max: 59 },
    { min: 0, max: 23 },
    { min: 1, max: 31 },
    { min: 1, max: 12 },
    { min: 0, max: 6 },
  ];

  const fieldNames = ['minute', 'hour', 'dayOfMonth', 'month', 'dayOfWeek'] as const;

  const result: CronExpression = {
    minute: [],
    hour: [],
    dayOfMonth: [],
    month: [],
    dayOfWeek: [],
  };

  for (let i = 0; i < 5; i++) {
    result[fieldNames[i]] = parseField(fields[i], ranges[i].min, ranges[i].max);
  }

  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  if (field === '*') {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  if (field.includes('/')) {
    const [rangePart, stepStr] = field.split('/');
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    const values: number[] = [];

    if (rangePart === '*') {
      for (let i = min; i <= max; i += step) {
        values.push(i);
      }
    } else if (rangePart.includes('-')) {
      const [startStr, endStr] = rangePart.split('-');
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);

      validateRange(start, end, min, max);

      for (let i = start; i <= end; i += step) {
        values.push(i);
      }
    } else {
      const val = parseInt(rangePart, 10);
      validateValue(val, min, max);
      values.push(val);
    }

    return values;
  }

  if (field.includes('-')) {
    const [startStr, endStr] = field.split('-');
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    validateRange(start, end, min, max);

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  if (field.includes(',')) {
    const values = field.split(',').map((v) => {
      const num = parseInt(v.trim(), 10);
      validateValue(num, min, max);
      return num;
    });

    return [...new Set(values)].sort((a, b) => a - b);
  }

  const num = parseInt(field, 10);
  validateValue(num, min, max);
  return [num];
}

function validateValue(value: number, min: number, max: number): void {
  if (isNaN(value) || value < min || value > max) {
    throw new Error(`Value ${value} is out of range [${min}, ${max}]`);
  }
}

function validateRange(start: number, end: number, min: number, max: number): void {
  if (isNaN(start) || isNaN(end)) {
    throw new Error('Invalid range');
  }
  if (start < min || end > max || start > end) {
    throw new Error(`Range [${start}, ${end}] is invalid or out of bounds [${min}, ${max}]`);
  }
}

