  const parts = field.split(',');

  for (const part of parts) {
    if (part.includes('/')) {
      const [range, step] = part.split('/');
      const stepNum = parseInt(step, 10);

      if (isNaN(stepNum) || stepNum <= 0) {
        throw new Error(`Invalid step value: ${step}`);
      }

      let rangeMin = min;
      let rangeMax = max;

      if (range !== '*') {
        if (range.includes('-')) {
          const [startStr, endStr] = range.split('-');
          rangeMin = parseInt(startStr, 10);
          rangeMax = parseInt(endStr, 10);

          if (isNaN(rangeMin) || isNaN(rangeMax)) {
            throw new Error(`Invalid range: ${range}`);
          }
        } else {
          rangeMin = parseInt(range, 10);
          if (isNaN(rangeMin)) {
            throw new Error(`Invalid value: ${range}`);
          }
          rangeMax = max;
        }
      }

      if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
        throw new Error(`Range ${rangeMin}-${rangeMax} out of bounds [${min}, ${max}]`);
      }

      for (let i = rangeMin; i <= rangeMax; i += stepNum) {
        values.add(i);
      }
    } else if (part.includes('-')) {
      const [startStr, endStr] = part.split('-');
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);

      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range: ${part}`);
      }

      if (start < min || end > max || start > end) {
        throw new Error(`Range ${start}-${end} out of bounds [${min}, ${max}]`);
      }

      for (let i = start; i <= end; i++) {
        values.add(i);
      }
    } else if (part === '*') {
      for (let i = min; i <= max; i++) {
        values.add(i);
      }
    } else {
      const num = parseInt(part, 10);

      if (isNaN(num)) {
        throw new Error(`Invalid value: ${part}`);
      }

      if (num < min || num > max) {
        throw new Error(`Value ${num} out of bounds [${min}, ${max}]`);
      }

      values.add(num);
    }
  }

  if (max === 7 && values.has(7)) {
    values.delete(7);
    values.add(0);
  }

  return Array.from(values).sort((a, b) => a - b);
}

