  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 }
};

const parseField = (field: string, min: number, max: number): number[] => {
  const values = new Set<number>();
  const parts = field.split(',');

  for (const part of parts.map(p => p.trim())) {
    // Handle step values
    if (part.includes('/')) {
      const [range, stepStr] = part.split('/');
      const step = parseInt(stepStr, 10);

      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: ${stepStr}`);
      }

      let rangeMin = min;
      let rangeMax = max;

      if (range !== '*') {
        if (range.includes('-')) {
          const [start, end] = range.split('-');
          rangeMin = parseInt(start, 10);
          rangeMax = parseInt(end, 10);
          if (isNaN(rangeMin) || isNaN(rangeMax)) {
            throw new Error(`Invalid range: ${range}`);
          }
        } else {
          rangeMin = parseInt(range, 10);
          rangeMax = rangeMin;
          if (isNaN(rangeMin)) {
            throw new Error(`Invalid value: ${range}`);
          }
        }
      }

      if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
        throw new Error(`Range out of bounds: ${rangeMin}-${rangeMax}`);
      }

      for (let i = rangeMin; i <= rangeMax; i += step) {
        values.add(i);
      }
      continue;
    }

    // Handle ranges
    if (part.includes('-')) {
      const [start, end] = part.split('-');
      const startNum = parseInt(start, 10);
      const endNum = parseInt(end, 10);

      if (isNaN(startNum) || isNaN(endNum)) {
        throw new Error(`Invalid range: ${part}`);
      }

      if (startNum < min || endNum > max || startNum > endNum) {
        throw new Error(`Range out of bounds: ${startNum}-${endNum}`);
      }

      for (let i = startNum; i <= endNum; i++) {
        values.add(i);
      }
      continue;
    }

    // Handle wildcard
    if (part === '*') {
      for (let i = min; i <= max; i++) {
        values.add(i);
      }
      continue;
    }

    // Handle single values
    const num = parseInt(part, 10);
    if (isNaN(num)) {
      throw new Error(`Invalid value: ${part}`);
    }

    if (num < min || num > max) {
      throw new Error(`Value out of bounds: ${num}`);
    }

    values.add(num);
  }

  return Array.from(values).sort((a, b) => a - b);
};

