  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 }
};

type FieldName = keyof typeof RANGES;

function parseField(field: string, fieldName: FieldName): number[] {
  const range = RANGES[fieldName];
  const values: number[] = [];

  if (field === '*') {
    for (let i = range.min; i <= range.max; i++) {
      values.push(i);
    }
    return values;
  }

  if (field.includes('/')) {
    const [baseField, stepStr] = field.split('/');
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    if (baseField === '*') {
      for (let i = range.min; i <= range.max; i += step) {
        values.push(i);
      }
    } else if (baseField.includes('-')) {
      const [startStr, endStr] = baseField.split('-');
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      for (let i = start; i <= end; i += step) {
        if (i >= range.min && i <= range.max) {
          values.push(i);
        }
      }
    } else {
      const start = parseInt(baseField, 10);
      for (let i = start; i <= range.max; i += step) {
        if (i >= range.min && i <= range.max) {
          values.push(i);
        }
      }
    }
    return values.sort((a, b) => a - b);
  }

  if (field.includes(',')) {
    const parts = field.split(',');
    for (const part of parts) {
      const parsed = parseField(part.trim(), fieldName);
      values.push(...parsed);
    }
    return Array.from(new Set(values)).sort((a, b) => a - b);
  }

  if (field.includes('-')) {
    const [startStr, endStr] = field.split('-');
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    for (let i = start; i <= end; i++) {
      if (i >= range.min && i <= range.max) {
        values.push(i);
      }
    }
    return values;
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid cron field value: ${field}`);
  }
  if (num >= range.min && num <= range.max) {
    values.push(num);
  }
  return values;
}

