function parseField(field: string, min: number, max: number): number[] {
  if (field === '*') {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  if (field.includes('/')) {
    const [range, step] = field.split('/');
    const stepValue = parseInt(step, 10);

    if (isNaN(stepValue) || stepValue <= 0) {
      throw new Error(`Invalid step value: ${step}`);
    }

    let start = min;
    let end = max;

    if (range !== '*') {
      if (range.includes('-')) {
        const [rangeStart, rangeEnd] = range.split('-');
        start = parseInt(rangeStart, 10);
        end = parseInt(rangeEnd, 10);

        if (isNaN(start) || isNaN(end)) {
          throw new Error(`Invalid range: ${range}`);
        }
      } else {
        start = parseInt(range, 10);

        if (isNaN(start)) {
          throw new Error(`Invalid value: ${range}`);
        }

        end = start;
      }
    }

    validateRange(start, end, min, max);

    const result: number[] = [];
    for (let i = start; i <= end; i += stepValue) {
      result.push(i);
    }
    return result;
  }

  if (field.includes('-')) {
    const parts = field.split('-');
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${field}`);
    }

    validateRange(start, end, min, max);

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  if (field.includes(',')) {
    const values = field.split(',').map((v) => {
      const num = parseInt(v.trim(), 10);
      if (isNaN(num)) {
        throw new Error(`Invalid value in list: ${v}`);
      }
      return num;
    });

    for (const value of values) {
      if (value < min || value > max) {
        throw new Error(`Value ${value} out of range [${min}, ${max}]`);
      }
    }

    return [...new Set(values)].sort((a, b) => a - b);
  }

  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value: ${field}`);
  }

  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }

  return [value];
}

function validateRange(
  start: number,
  end: number,
  min: number,
  max: number
): void {
  if (start < min || start > max) {
    throw new Error(`Start value ${start} out of range [${min}, ${max}]`);
  }
  if (end < min || end > max) {
    throw new Error(`End value ${end} out of range [${min}, ${max}]`);
  }
  if (start > end) {
    throw new Error(`Invalid range: start ${start} is greater than end ${end}`);
  }
}

