        }
      } else {
        const num = parseInt(part, 10);

        if (isNaN(num)) {
          throw new Error(`Invalid value: ${part}`);
        }

        values.add(num);
      }
    }

    for (const val of values) {
      if (val < min || val > max) {
        throw new Error(`Value ${val} out of range [${min}, ${max}]`);
      }
    }

    return Array.from(values).sort((a, b) => a - b);
  };

  return {
    minute: parseField(fields[0], ranges[0].min, ranges[0].max),
    hour: parseField(fields[1], ranges[1].min, ranges[1].max),
    dayOfMonth: parseField(fields[2], ranges[2].min, ranges[2].max),
    month: parseField(fields[3], ranges[3].min, ranges[3].max),
    dayOfWeek: parseField(fields[4], ranges[4].min, ranges[4].max),
