function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const ranges = [
    { min: 0, max: 59 },   // minute
    { min: 0, max: 23 },   // hour
    { min: 1, max: 31 },   // dayOfMonth
    { min: 1, max: 12 },   // month
    { min: 0, max: 6 },    // dayOfWeek
  ];

  const result: CronResult = {
    minute: [],
    hour: [],
    dayOfMonth: [],
    month: [],
    dayOfWeek: [],
  };

  const keys: (keyof CronResult)[] = ['minute', 'hour', 'dayOfMonth', 'month', 'dayOfWeek'];

  for (let i = 0; i < 5; i++) {
    const field = fields[i];
    const range = ranges[i];
    result[keys[i]] = parseField(field, range.min, range.max);
  }

  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const valueSet = new Set<number>();

  if (field === '*') {
    for (let i = min; i <= max; i++) {
      valueSet.add(i);
    }
  } else if (field.startsWith('*/')) {
    const step = parseInt(field.substring(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${field}`);
    }
    for (let i = min; i <= max; i += step) {
      valueSet.add(i);
    }
  } else if (field.includes('-')) {
    const parts = field.split('-');
    if (parts.length !== 2) {
      throw new Error(`Invalid range: ${field}`);
    }
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end) || start > end) {
      throw new Error(`Invalid range: ${field}`);
    }
    if (start < min || end > max) {
      throw new Error(`Range out of bounds: ${field} (valid: ${min}-${max})`);
    }
    for (let i = start; i <= end; i++) {
      valueSet.add(i);
    }
  } else if (field.includes(',')) {
    const parts = field.split(',');
    for (const part of parts) {
      const num = parseInt(part.trim(), 10);
      if (isNaN(num)) {
        throw new Error(`Invalid value: ${part}`);
      }
      if (num < min || num > max) {
        throw new Error(`Value out of range: ${num} (valid: ${min}-${max})`);
      }
      valueSet.add(num);
    }
  } else {
    const num = parseInt(field, 10);
    if (isNaN(num)) {
      throw new Error(`Invalid value: ${field}`);
    }
    if (num < min || num > max) {
      throw new Error(`Value out of range: ${num} (valid: ${min}-${max})`);
    }
    valueSet.add(num);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

