class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: { maxTokens: number; refillRate: number; refillIntervalMs: number }) {
    this.maxTokens = Math.max(0, options.maxTokens);
    this.refillRate = Math.max(0, options.refillRate);
    this.refillIntervalMs = Math.max(1, options.refillIntervalMs);
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsedMs = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsedMs / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    const amount = Math.max(0, tokens);
    if (amount === 0) return true;

    this.refill();

    if (this.currentTokens >= amount) {
      this.currentTokens -= amount;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    const amount = Math.max(0, tokens);
    if (amount === 0) return;

    if (this.refillRate === 0) {
      this.refill();
      if (this.currentTokens < amount) {
        throw new Error('Insufficient tokens with zero refill rate');
      }
      this.currentTokens -= amount;
      return;
    }

    while (true) {
      this.refill();

      if (this.currentTokens >= amount) {
        this.currentTokens -= amount;
        return;
      }

      const now = Date.now();
      const needed = amount - this.currentTokens;
      const intervalsNeeded = Math.ceil(needed / this.refillRate);
      const timeToWait = this.lastRefillTime + intervalsNeeded * this.refillIntervalMs - now;

      await new Promise(resolve => setTimeout(resolve, Math.max(1, Math.ceil(timeToWait))));
    }
  }
}

