function expandField(field: string, fieldType: CronField): number[] {
  const { min, max } = CRON_RANGES[fieldType];
  const values: Set<number> = new Set();

  const parts = field.split(',');

  for (const part of parts) {
    if (part.includes('/')) {
      const [range, step] = part.split('/');
      const stepNum = parseInt(step, 10);

      if (isNaN(stepNum) || stepNum <= 0) {
        throw new Error(`Invalid step value: ${step}`);
      }

      let rangeMin = min;
      let rangeMax = max;

      if (range !== '*') {
        if (range.includes('-')) {
          const [start, end] = range.split('-');
          rangeMin = parseInt(start, 10);
          rangeMax = parseInt(end, 10);

          if (isNaN(rangeMin) || isNaN(rangeMax)) {
            throw new Error(`Invalid range: ${range}`);
          }
        } else {
          rangeMin = parseInt(range, 10);
          if (isNaN(rangeMin)) {
            throw new Error(`Invalid range: ${range}`);
          }
        }
      }

      if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
        throw new Error(`Range out of bounds for ${fieldType}: ${rangeMin}-${rangeMax}`);
      }

      for (let i = rangeMin; i <= rangeMax; i += stepNum) {
        values.add(i);
      }
    } else if (part.includes('-')) {
      const [start, end] = part.split('-');
      const startNum = parseInt(start, 10);
      const endNum = parseInt(end, 10);

      if (isNaN(startNum) || isNaN(endNum)) {
        throw new Error(`Invalid range: ${part}`);
      }

      if (startNum < min || endNum > max || startNum > endNum) {
        throw new Error(`Invalid range for ${fieldType}: ${startNum}-${endNum}`);
      }

      for (let i = startNum; i <= endNum; i++) {
        values.add(i);
      }
    } else if (part === '*') {
      for (let i = min; i <= max; i++) {
        values.add(i);
      }
    } else {
      const num = parseInt(part, 10);

      if (isNaN(num)) {
        throw new Error(`Invalid value: ${part}`);
      }

      if (num < min || num > max) {
        throw new Error(`Value out of range for ${fieldType}: ${num}`);
      }

      values.add(num);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

