interface CronParsed {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function parseCron(expression: string): CronParsed {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error('Cron expression must have exactly 5 fields');
  }

  const ranges = [
    { name: 'minute', min: 0, max: 59 },
    { name: 'hour', min: 0, max: 23 },
    { name: 'dayOfMonth', min: 1, max: 31 },
    { name: 'month', min: 1, max: 12 },
    { name: 'dayOfWeek', min: 0, max: 6 },
  ];

  const result: CronParsed = {
    minute: [],
    hour: [],
    dayOfMonth: [],
    month: [],
    dayOfWeek: [],
  };

  fields.forEach((field, index) => {
    const { name, min, max } = ranges[index];
    const values = parseField(field, min, max);
    (result as any)[name] = values;
  });

  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const values: number[] = [];
  const parts = field.split(',');

  parts.forEach((part) => {
    if (part.includes('/')) {
      const [range, step] = part.split('/');
      const stepNum = parseInt(step, 10);

      if (isNaN(stepNum) || stepNum <= 0) {
        throw new Error(`Invalid step value: ${step}`);
      }

      let rangeMin = min;
      let rangeMax = max;

      if (range === '*') {
        rangeMin = min;
        rangeMax = max;
      } else if (range.includes('-')) {
        [rangeMin, rangeMax] = parseRange(range, min, max);
      } else {
        const num = parseInt(range, 10);
        if (isNaN(num) || num < min || num > max) {
          throw new Error(`Invalid value: ${range} (must be between ${min} and ${max})`);
        }
        rangeMin = num;
        rangeMax = max;
      }

      for (let i = rangeMin; i <= rangeMax; i += stepNum) {
        if (i >= min && i <= max) {
          values.push(i);
        }
      }
    } else if (part.includes('-')) {
      const [start, end] = parseRange(part, min, max);
      for (let i = start; i <= end; i++) {
        values.push(i);
      }
    } else if (part === '*') {
      for (let i = min; i <= max; i++) {
        values.push(i);
      }
    } else {
      const num = parseInt(part, 10);
      if (isNaN(num) || num < min || num > max) {
        throw new Error(`Invalid value: ${part} (must be between ${min} and ${max})`);
      }
      values.push(num);
    }
  });

  return [...new Set(values)].sort((a, b) => a - b);
}

function parseRange(range: string, min: number, max: number): [number, number] {
  const [start, end] = range.split('-').map((v) => parseInt(v, 10));

  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range: ${range}`);
  }

  if (start < min || start > max || end < min || end > max) {
    throw new Error(`Range values out of bounds: ${range} (valid range: ${min}-${max})`);
  }

  if (start > end) {
    throw new Error(`Invalid range: start (${start}) is greater than end (${end})`);
  }

  return [start, end];
}

