interface CronParsed {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  if (field === '*') {
    for (let i = min; i <= max; i++) {
      values.add(i);
    }
  } else if (field.startsWith('*/')) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${field}`);
    }
    for (let i = min; i <= max; i += step) {
      values.add(i);
    }
  } else {
    const parts = field.split(',');
    for (const part of parts) {
      if (part.includes('-')) {
        const rangeParts = part.split('-');
        if (rangeParts.length !== 2) {
          throw new Error(`Invalid range: ${part}`);
        }
        const start = parseInt(rangeParts[0], 10);
        const end = parseInt(rangeParts[1], 10);
        if (isNaN(start) || isNaN(end)) {
          throw new Error(`Invalid range: ${part}`);
        }
        if (start < min || start > max) {
          throw new Error(`Range start ${start} out of bounds [${min}, ${max}]`);
        }
        if (end < min || end > max) {
          throw new Error(`Range end ${end} out of bounds [${min}, ${max}]`);
        }
        if (start > end) {
          throw new Error(`Invalid range: start ${start} > end ${end}`);
        }
        for (let i = start; i <= end; i++) {
          values.add(i);
        }
      } else {
        const value = parseInt(part, 10);
        if (isNaN(value)) {
          throw new Error(`Invalid value: ${part}`);
        }
        if (value < min || value > max) {
          throw new Error(`Value ${value} out of range [${min}, ${max}]`);
        }
        values.add(value);
      }
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

function parseCron(expression: string): CronParsed {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error('Cron expression must have exactly 5 fields');
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields;

  return {
    minute: parseField(minuteStr, 0, 59),
    hour: parseField(hourStr, 0, 23),
    dayOfMonth: parseField(dayOfMonthStr, 1, 31),
    month: parseField(monthStr, 1, 12),
    dayOfWeek: parseField(dayOfWeekStr, 1, 7),
  };
}

export default parseCron;

class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;
  private waitQueue: Array<{ tokens: number; resolve: () => void }> = [];
  private checkInterval: NodeJS.Timeout | null = null;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const timeSinceLastRefill = now - this.lastRefillTime;
    const tokensToAdd =
      (timeSinceLastRefill / this.refillIntervalMs) * this.refillRate;

    this.tokens = Math.min(this.maxTokens, this.tokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private processWaitQueue(): void {
    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];
      if (this.tokens >= next.tokens) {
        this.tokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
      } else {
        break;
      }
    }
  }

  private startCheckInterval(): void {
    if (this.checkInterval !== null) return;

    this.checkInterval = setInterval(() => {
      this.refill();
      this.processWaitQueue();

      if (this.waitQueue.length === 0) {
        clearInterval(this.checkInterval!);
        this.checkInterval = null;
      }
    }, Math.max(1, this.refillIntervalMs / 10));
  }

  tryConsume(tokens: number = 1): boolean {
    this.refill();

    if (tokens <= 0) {
      return true;
    }

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) {
      return;
    }

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return;
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.startCheckInterval();
    });
  }
}

export default RateLimiter;

